  1→import { useState, useMemo } from 'react';
  2→import { View, Text, StyleSheet, FlatList, Pressable, RefreshControl } from 'react-native';
  3→import { useRouter } from 'expo-router';
  4→import { SafeAreaView } from 'react-native-safe-area-context';
  5→import { useCachedQuery } from '@/hooks/useCachedQuery';
  6→import { supabase } from '@/lib/supabase';
  7→import { Card } from '@/components/ui/Card';
  8→import { Badge } from '@/components/ui/Badge';
  9→import { EmptyState } from '@/components/ui/EmptyState';
 10→import { SkeletonCard } from '@/components/ui/Skeleton';
 11→import { OfflineBanner } from '@/components/ui/OfflineBanner';
 12→import theme from '@/theme';
 13→import type { CampaignRedemption } from '@astrolab/shared';
 14→
 15→type Filter = 'all' | 'active' | 'used' | 'expired';
 16→
 17→export default function OffersScreen() {
 18→  const router = useRouter();
 19→  const [filter, setFilter] = useState<Filter>('all');
 20→
 21→  const { data: offers, loading, refresh } = useCachedQuery<CampaignRedemption[]>(
 22→    'all_offers',
 23→    async () => {
 24→      const { data, error } = await supabase
 25→        .from('campaign_redemptions')
 26→        .select('*, campaigns(title, message, offer_type, offer_value, offer_description, merchants(name, logo_url))')
 27→        .order('created_at', { ascending: false });
 28→      if (error) throw error;
 29→      return (data as unknown as CampaignRedemption[]) ?? [];
 30→    },
 31→    []
 32→  );
 33→
 34→  const filtered = useMemo(() => {
 35→    if (!offers) return [];
 36→    const now = new Date();
 37→    return offers.filter((o) => {
 38→      const isExpired = o.expires_at ? new Date(o.expires_at) < now : false;
 39→      if (filter === 'active') return !o.is_redeemed && !isExpired;
 40→      if (filter === 'used') return o.is_redeemed;
 41→      if (filter === 'expired') return isExpired && !o.is_redeemed;
 42→      return true;
 43→    });
 44→  }, [offers, filter]);
 45→
 46→  const getStatus = (o: CampaignRedemption) => {
 47→    if (o.is_redeemed) return { label: 'Utilisee', variant: 'neutral' as const };
 48→    if (o.expires_at && new Date(o.expires_at) < new Date()) return { label: 'Expiree', variant: 'error' as const };
 49→    return { label: 'Active', variant: 'success' as const };
 50→  };
 51→
 52→  const filters: { key: Filter; label: string }[] = [
 53→    { key: 'all', label: 'Toutes' },
 54→    { key: 'active', label: 'Actives' },
 55→    { key: 'used', label: 'Utilisees' },
 56→    { key: 'expired', label: 'Expirees' },
 57→  ];
 58→
 59→  return (
 60→    <SafeAreaView style={styles.container} edges={['top']}>
 61→      <OfflineBanner />
 62→      <View style={styles.header}>
 63→        <Text style={styles.title}>Mes offres</Text>
 64→      </View>
 65→
 66→      {/* Filters */}
 67→      <View style={styles.filterRow}>
 68→        {filters.map((f) => (
 69→          <Pressable
 70→            key={f.key}
 71→            onPress={() => setFilter(f.key)}
 72→            style={[styles.filterChip, filter === f.key && styles.filterChipActive]}
 73→          >
 74→            <Text style={[styles.filterText, filter === f.key && styles.filterTextActive]}>
 75→              {f.label}
 76→            </Text>
 77→          </Pressable>
 78→        ))}
 79→      </View>
 80→
 81→      {loading && !offers?.length ? (
 82→        <View style={styles.skeletons}><SkeletonCard /><SkeletonCard /><SkeletonCard /></View>
 83→      ) : !filtered.length ? (
 84→        <EmptyState
 85→          icon="🎁"
 86→          title="Aucune offre"
 87→          description="Vos offres promotionnelles apparaitront ici."
 88→        />
 89→      ) : (
 90→        <FlatList
 91→          data={filtered}
 92→          keyExtractor={(item) => item.id}
 93→          refreshControl={<RefreshControl refreshing={false} onRefresh={refresh} tintColor={theme.colors.primary} />}
 94→          contentContainerStyle={styles.list}
 95→          renderItem={({ item }) => {
 96→            const campaign = (item as any).campaigns;
 97→            const merchant = campaign?.merchants;
 98→            const status = getStatus(item);
 99→            return (
100→              <Pressable onPress={() => router.push(`/(tabs)/offers/${item.id}`)}>
101→                <Card style={styles.offerCard}>
102→                  <View style={styles.offerHeader}>
103→                    <View style={{ flex: 1 }}>
104→                      <Text style={styles.offerTitle}>{campaign?.title ?? 'Offre'}</Text>
105→                      <Text style={styles.merchantName}>{merchant?.name ?? ''}</Text>
106→                    </View>
107→                    <Badge variant={status.variant}>{status.label}</Badge>
108→                  </View>
109→                  <Text style={styles.offerDesc} numberOfLines={2}>
110→                    {campaign?.offer_description ?? campaign?.message ?? ''}
111→                  </Text>
112→                  {item.expires_at && (
113→                    <Text style={styles.offerExpiry}>
114→                      Expire le {new Date(item.expires_at).toLocaleDateString('fr-FR')}
115→                    </Text>
116→                  )}
117→                </Card>
118→              </Pressable>
119→            );
120→          }}
121→        />
122→      )}
123→    </SafeAreaView>
124→  );
125→}
126→
127→const styles = StyleSheet.create({
128→  container: { flex: 1, backgroundColor: theme.colors.background },
129→  header: { paddingHorizontal: theme.spacing.lg, paddingTop: theme.spacing.md, paddingBottom: theme.spacing.sm },
130→  title: { fontSize: theme.fontSize['2xl'], fontWeight: '700', color: theme.colors.text },
131→  filterRow: { flexDirection: 'row', paddingHorizontal: theme.spacing.lg, gap: theme.spacing.sm, marginBottom: theme.spacing.md },
132→  filterChip: { paddingHorizontal: theme.spacing.md, paddingVertical: theme.spacing.xs, borderRadius: theme.borderRadius.full, backgroundColor: theme.colors.surface, borderWidth: 1, borderColor: theme.colors.border },
133→  filterChipActive: { backgroundColor: theme.colors.primary, borderColor: theme.colors.primary },
134→  filterText: { fontSize: theme.fontSize.sm, color: theme.colors.textMuted, fontWeight: '500' },
135→  filterTextActive: { color: '#fff' },
136→  skeletons: { padding: theme.spacing.lg, gap: theme.spacing.md },
137→  list: { padding: theme.spacing.lg, gap: theme.spacing.md, paddingBottom: 100 },
138→  offerCard: { gap: theme.spacing.sm },
139→  offerHeader: { flexDirection: 'row', alignItems: 'flex-start', justifyContent: 'space-between' },
140→  offerTitle: { fontSize: theme.fontSize.base, fontWeight: '600', color: theme.colors.text },
141→  merchantName: { fontSize: theme.fontSize.xs, color: theme.colors.textMuted, marginTop: 2 },
142→  offerDesc: { fontSize: theme.fontSize.sm, color: theme.colors.textMuted, lineHeight: 20 },
143→  offerExpiry: { fontSize: theme.fontSize.xs, color: theme.colors.textMuted },
144→});
