  1→import { View, Text, StyleSheet, ScrollView } from 'react-native';
  2→import { useLocalSearchParams, Stack } from 'expo-router';
  3→import { SafeAreaView } from 'react-native-safe-area-context';
  4→import { useCachedQuery } from '@/hooks/useCachedQuery';
  5→import { useBrightness } from '@/hooks/useBrightness';
  6→import { supabase } from '@/lib/supabase';
  7→import { OfferQRDisplay } from '@/components/offers/OfferQRDisplay';
  8→import { Card } from '@/components/ui/Card';
  9→import { Badge } from '@/components/ui/Badge';
 10→import { SkeletonCard } from '@/components/ui/Skeleton';
 11→import theme from '@/theme';
 12→import type { CampaignRedemption } from '@astrolab/shared';
 13→
 14→export default function OfferDetailScreen() {
 15→  const { offerId } = useLocalSearchParams<{ offerId: string }>();
 16→
 17→  useBrightness(true);
 18→
 19→  const { data: offer, loading } = useCachedQuery<CampaignRedemption | null>(
 20→    `offer_${offerId}`,
 21→    async () => {
 22→      const { data, error } = await supabase
 23→        .from('campaign_redemptions')
 24→        .select('*, campaigns(title, message, offer_type, offer_value, offer_description, merchants(name, logo_url))')
 25→        .eq('id', offerId)
 26→        .single();
 27→      if (error) throw error;
 28→      return data as unknown as CampaignRedemption;
 29→    },
 30→    [offerId]
 31→  );
 32→
 33→  const campaign = (offer as any)?.campaigns;
 34→  const merchant = campaign?.merchants;
 35→  const isExpired = offer?.expires_at ? new Date(offer.expires_at) < new Date() : false;
 36→  const isUsed = offer?.is_redeemed ?? false;
 37→
 38→  if (loading) {
 39→    return (
 40→      <SafeAreaView style={styles.container}>
 41→        <Stack.Screen options={{ headerShown: true, title: 'Chargement...' }} />
 42→        <View style={styles.content}><SkeletonCard /><SkeletonCard /></View>
 43→      </SafeAreaView>
 44→    );
 45→  }
 46→
 47→  if (!offer) {
 48→    return (
 49→      <SafeAreaView style={styles.container}>
 50→        <Stack.Screen options={{ headerShown: true, title: 'Offre introuvable' }} />
 51→        <View style={styles.content}>
 52→          <Text style={styles.errorText}>Cette offre n'existe pas.</Text>
 53→        </View>
 54→      </SafeAreaView>
 55→    );
 56→  }
 57→
 58→  return (
 59→    <SafeAreaView style={styles.container} edges={['top']}>
 60→      <Stack.Screen
 61→        options={{
 62→          headerShown: true,
 63→          title: merchant?.name ?? 'Offre',
 64→          headerStyle: { backgroundColor: theme.colors.background },
 65→          headerTintColor: theme.colors.text,
 66→        }}
 67→      />
 68→      <ScrollView contentContainerStyle={styles.content}>
 69→        {/* QR */}
 70→        <OfferQRDisplay
 71→          value={offer.redemption_token}
 72→          status={isUsed ? 'used' : isExpired ? 'expired' : 'active'}
 73→          usedAt={offer.redeemed_at ?? undefined}
 74→        />
 75→
 76→        {/* Details */}
 77→        <Card>
 78→          <View style={styles.detailHeader}>
 79→            <Text style={styles.offerTitle}>{campaign?.title ?? 'Offre'}</Text>
 80→            <Badge variant={isUsed ? 'neutral' : isExpired ? 'error' : 'success'}>
 81→              {isUsed ? 'Utilisee' : isExpired ? 'Expiree' : 'Active'}
 82→            </Badge>
 83→          </View>
 84→          <Text style={styles.offerDesc}>
 85→            {campaign?.offer_description ?? campaign?.message ?? ''}
 86→          </Text>
 87→
 88→          <View style={styles.metaRow}>
 89→            <View style={styles.metaItem}>
 90→              <Text style={styles.metaLabel}>Commercant</Text>
 91→              <Text style={styles.metaValue}>{merchant?.name ?? '—'}</Text>
 92→            </View>
 93→            {offer.expires_at && (
 94→              <View style={styles.metaItem}>
 95→                <Text style={styles.metaLabel}>Expire le</Text>
 96→                <Text style={styles.metaValue}>
 97→                  {new Date(offer.expires_at).toLocaleDateString('fr-FR')}
 98→                </Text>
 99→              </View>
100→            )}
101→            {offer.redeemed_at && (
102→              <View style={styles.metaItem}>
103→                <Text style={styles.metaLabel}>Utilisee le</Text>
104→                <Text style={styles.metaValue}>
105→                  {new Date(offer.redeemed_at).toLocaleDateString('fr-FR')}
106→                </Text>
107→              </View>
108→            )}
109→          </View>
110→        </Card>
111→
112→        {/* Instructions */}
113→        {!isUsed && !isExpired && (
114→          <Card style={styles.instructionCard}>
115→            <Text style={styles.instructionTitle}>Comment utiliser cette offre ?</Text>
116→            <Text style={styles.instructionText}>
117→              1. Presentez le QR code ci-dessus au commercant{'\n'}
118→              2. Le commercant scanne le QR code{'\n'}
119→              3. La reduction est appliquee automatiquement
120→            </Text>
121→          </Card>
122→        )}
123→      </ScrollView>
124→    </SafeAreaView>
125→  );
126→}
