129→  container: { flex: 1, backgroundColor: theme.colors.background },
130→  content: { padding: theme.spacing.lg, gap: theme.spacing.md, paddingBottom: 100 },
131→  detailHeader: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', marginBottom: theme.spacing.sm },
132→  offerTitle: { fontSize: theme.fontSize.lg, fontWeight: '700', color: theme.colors.text, flex: 1 },
133→  offerDesc: { fontSize: theme.fontSize.base, color: theme.colors.textMuted, lineHeight: 22, marginBottom: theme.spacing.md },
134→  metaRow: { gap: theme.spacing.sm },
135→  metaItem: { flexDirection: 'row', justifyContent: 'space-between', paddingVertical: theme.spacing.xs },
136→  metaLabel: { fontSize: theme.fontSize.sm, color: theme.colors.textMuted },
137→  metaValue: { fontSize: theme.fontSize.sm, fontWeight: '500', color: theme.colors.text },
138→  instructionCard: { backgroundColor: `${theme.colors.primary}10` },
139→  instructionTitle: { fontSize: theme.fontSize.base, fontWeight: '600', color: theme.colors.primary, marginBottom: theme.spacing.sm },
140→  instructionText: { fontSize: theme.fontSize.sm, color: theme.colors.text, lineHeight: 22 },
141→  errorText: { fontSize: theme.fontSize.base, color: theme.colors.textMuted, textAlign: 'center', paddingVertical: theme.spacing.xl },
