  1→import { View, Text, StyleSheet } from 'react-native';
  2→import { useLocalSearchParams, Stack, useRouter } from 'expo-router';
  3→import { SafeAreaView } from 'react-native-safe-area-context';
  4→import { useCachedQuery } from '@/hooks/useCachedQuery';
  5→import { useBrightness } from '@/hooks/useBrightness';
  6→import { useAuth } from '@/contexts/AuthContext';
  7→import { supabase } from '@/lib/supabase';
  8→import { OfferQRDisplay } from '@/components/offers/OfferQRDisplay';
  9→import { Card } from '@/components/ui/Card';
 10→import { Badge } from '@/components/ui/Badge';
 11→import { Button } from '@/components/ui/Button';
 12→import { SkeletonCard } from '@/components/ui/Skeleton';
 13→import theme from '@/theme';
 14→import type { CampaignRedemption } from '@astrolab/shared';
 15→
 16→export default function DeepLinkOfferScreen() {
 17→  const { token } = useLocalSearchParams<{ token: string }>();
 18→  const { user } = useAuth();
 19→  const router = useRouter();
 20→
 21→  useBrightness(true);
 22→
 23→  const { data: offer, loading } = useCachedQuery<CampaignRedemption | null>(
 24→    `deeplink_offer_${token}`,
 25→    async () => {
 26→      if (!token) return null;
 27→      const { data, error } = await supabase
 28→        .from('campaign_redemptions')
 29→        .select('*, campaigns(title, message, offer_type, offer_value, offer_description, merchants(name, logo_url))')
 30→        .eq('redemption_token', token)
 31→        .single();
 32→      if (error) throw error;
 33→      return data as unknown as CampaignRedemption;
 34→    },
 35→    [token]
 36→  );
 37→
 38→  const campaign = (offer as any)?.campaigns;
 39→  const merchant = campaign?.merchants;
 40→  const isExpired = offer?.expires_at ? new Date(offer.expires_at) < new Date() : false;
 41→  const isUsed = offer?.is_redeemed ?? false;
 42→
 43→  if (loading) {
 44→    return (
 45→      <SafeAreaView style={styles.container}>
 46→        <Stack.Screen options={{ title: 'Offre' }} />
 47→        <View style={styles.content}><SkeletonCard /></View>
 48→      </SafeAreaView>
 49→    );
 50→  }
 51→
 52→  if (!offer) {
 53→    return (
 54→      <SafeAreaView style={styles.container}>
 55→        <Stack.Screen options={{ title: 'Offre introuvable' }} />
 56→        <View style={styles.centered}>
 57→          <Text style={styles.emoji}>❌</Text>
 58→          <Text style={styles.errorTitle}>Offre introuvable</Text>
 59→          <Text style={styles.errorText}>Cette offre n'existe pas ou a ete supprimee.</Text>
 60→          {user && (
 61→            <Button onPress={() => router.replace('/(tabs)')}>
 62→              Retour a l'accueil
 63→            </Button>
 64→          )}
 65→        </View>
 66→      </SafeAreaView>
 67→    );
 68→  }
 69→
 70→  return (
 71→    <SafeAreaView style={styles.container}>
 72→      <Stack.Screen options={{ title: merchant?.name ?? 'Offre' }} />
 73→      <View style={styles.content}>
 74→        <OfferQRDisplay
 75→          value={offer.redemption_token}
 76→          status={isUsed ? 'used' : isExpired ? 'expired' : 'active'}
 77→          usedAt={offer.redeemed_at ?? undefined}
 78→        />
 79→
 80→        <Card>
 81→          <View style={styles.offerHeader}>
 82→            <Text style={styles.offerTitle}>{campaign?.title ?? 'Offre'}</Text>
 83→            <Badge variant={isUsed ? 'neutral' : isExpired ? 'error' : 'success'}>
 84→              {isUsed ? 'Utilisee' : isExpired ? 'Expiree' : 'Active'}
 85→            </Badge>
 86→          </View>
 87→          <Text style={styles.offerDesc}>{campaign?.offer_description ?? ''}</Text>
 88→          <Text style={styles.merchantText}>Chez {merchant?.name ?? '—'}</Text>
 89→        </Card>
 90→
 91→        {user && (
 92→          <Button variant="outline" onPress={() => router.replace('/(tabs)')}>
 93→            Retour a l'accueil
 94→          </Button>
 95→        )}
 96→      </View>
 97→    </SafeAreaView>
 98→  );
 99→}
