101→const styles = StyleSheet.create({
102→  container: { flex: 1, backgroundColor: theme.colors.background },
103→  content: { padding: theme.spacing.lg, gap: theme.spacing.md },
104→  centered: { flex: 1, justifyContent: 'center', alignItems: 'center', padding: theme.spacing.xl },
105→  emoji: { fontSize: 64, marginBottom: theme.spacing.md },
106→  errorTitle: { fontSize: theme.fontSize.xl, fontWeight: '700', color: theme.colors.text, marginBottom: theme.spacing.sm },
107→  errorText: { fontSize: theme.fontSize.base, color: theme.colors.textMuted, textAlign: 'center', marginBottom: theme.spacing.xl },
108→  offerHeader: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', marginBottom: theme.spacing.sm },
109→  offerTitle: { fontSize: theme.fontSize.lg, fontWeight: '700', color: theme.colors.text, flex: 1 },
110→  offerDesc: { fontSize: theme.fontSize.base, color: theme.colors.textMuted, lineHeight: 22 },
111→  merchantText: { fontSize: theme.fontSize.sm, color: theme.colors.primary, fontWeight: '500', marginTop: theme.spacing.sm },
